--- a/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp
@@ -1553,6 +1553,25 @@ Instruction *InstCombinerImpl::visitLShr(BinaryOperator &I) {
     // Reduce add-carry of bools to logic:
     // ((zext BoolX) + (zext BoolY)) >> 1 --> zext (BoolX && BoolY)
     Value *BoolX, *BoolY;
+    // ((A & C) + (B & C)) >> (K + 1) --> (A & B & C) >> K
+    // (where C = 1 << K)
+    if (match(Op0, m_Add(m_Value(X), m_Value(Y))) &&
+        (X->hasOneUse() || Y->hasOneUse() || Op0->hasOneUse())) {
+      Value *A, *B;
+      const APInt *C1, *C2;
+      if (match(X, m_And(m_Value(A), m_APInt(C1))) &&
+          match(Y, m_And(m_Value(B), m_APInt(C2))) &&
+          C1->eq(*C2) && C1->isPowerOf2() && C1->logBase2() == ShAmtC - 1) {
+        Value *And1 = Builder.CreateAnd(A, B);
+        Value *And2 = Builder.CreateAnd(And1, ConstantInt::get(Ty, *C1));
+        if (*C1 == 1) {
+            return replaceInstUsesWith(I, And2);
+        } else {
+            return BinaryOperator::CreateLShr(And2, ConstantInt::get(Ty, ShAmtC - 1));
+        }
+      }
+    }
+
